package main

import (
	"html/template"
	"log"
	"net/http"
	"time"
)

type Comment struct {
	Author    string
	CreatedAt time.Time
	BodyHTML  template.HTML
}

var comments = []Comment{
	{
		Author:    "Alice",
		CreatedAt: time.Now().Add(-3 * time.Hour),
		BodyHTML:  template.HTML("Hello <b>world</b>! This is <i>formatted</i>."),
	},
	{
		Author:    "Bob",
		CreatedAt: time.Now().Add(-90 * time.Minute),
		BodyHTML:  template.HTML("A link: <a href=\"https://example.com\" target=\"_blank\" rel=\"noopener noreferrer\">example</a>"),
	},
	{
		Author:    "Carol",
		CreatedAt: time.Now().Add(-10 * time.Minute),
		BodyHTML:  template.HTML("Lists:<ul><li>one</li><li>two</li></ul>"),
	},
}

var commentsTmpl = template.Must(template.New("comments").Parse(`<!doctype html>
<html lang="en">
<head>
	<meta charset="utf-8">
	<meta name="viewport" content="width=device-width, initial-scale=1">
	<title>Comments</title>
	<style>
		body { font-family: system-ui, -apple-system, Segoe UI, Roboto, sans-serif; margin: 2rem; line-height: 1.4; }
		.comment { border: 1px solid #ddd; border-radius: 10px; padding: 1rem; margin-bottom: 1rem; }
		.meta { color: #555; font-size: 0.9rem; margin-bottom: 0.5rem; }
		.author { font-weight: 600; color: #111; }
		.time { margin-left: 0.5rem; }
		.body { color: #111; }
	</style>
</head>
<body>
	<h1>User comments</h1>
	{{if .Comments}}
		{{range .Comments}}
			<div class="comment">
				<div class="meta">
					<span class="author">{{.Author}}</span>
					<span class="time">{{.CreatedAt.Format "2006-01-02 15:04"}}</span>
				</div>
				<div class="body">{{.BodyHTML}}</div>
			</div>
		{{end}}
	{{else}}
		<p>No comments yet.</p>
	{{end}}
</body>
</html>`))

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	data := struct {
		Comments []Comment
	}{
		Comments: comments,
	}
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := commentsTmpl.Execute(w, data); err != nil {
		http.Error(w, "template error", http.StatusInternalServerError)
		return
	}
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	log.Println("listening on http://localhost:8080/comments")
	log.Fatal(http.ListenAndServe(":8080", nil))
}